const Q2_OPTIONS = [["Problema operativo","Problema operativo"],["Oportunidad estratégica","Oportunidad estratégica"],["Requerimiento externo","Requerimiento externo"],["Mejora cultural","Mejora cultural"],["Otro","Otro"]];
const LEGACY_CHECK_VALUE_MAP = {
  q1: {
    "Sistema": "Sistema / herramienta",
    "Rol": "Rol / estructura",
    "Cultural": "Práctica cultural"
  },
  q2: {
    "Operativa": "Problema operativo",
    "Negocio": "Oportunidad estratégica",
    "Normativa": "Requerimiento externo",
    "Cliente": "Mejora cultural"
  }
};
function byId(id){ return document.getElementById(id); }
function lsGet(key, fallback=''){ try{ return localStorage.getItem(key) ?? fallback; }catch(e){ return fallback; } }
function lsSet(key, value){ try{ localStorage.setItem(key, value); }catch(e){} }
function parseJSON(value, fallback){ try{ return JSON.parse(value); }catch(e){ return fallback; } }
function escapeHtml(str=''){ return String(str).replace(/[&<>"']/g, s => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s])); }
function normalizeStoredChecks(groupName, values){
  const map = LEGACY_CHECK_VALUE_MAP[groupName] || {};
  const normalized = Array.from(new Set((Array.isArray(values) ? values : []).map(v => map[v] || v)));
  return normalized;
}
function buildChecks(containerId, name, options, storedKey){
  const wrap = byId(containerId);
  const selectedRaw = parseJSON(lsGet(storedKey,'[]'), []);
  const selected = normalizeStoredChecks(name, selectedRaw);
  if(JSON.stringify(selected) !== JSON.stringify(selectedRaw)) lsSet(storedKey, JSON.stringify(selected));
  wrap.innerHTML = options.map(([value,label]) => `<label class="option"><input type="checkbox" data-group="${name}" value="${value}" ${selected.includes(value) ? 'checked' : ''}> <span>${label}</span></label>`).join('');
}
function saveChecks(groupName, storageKey){
  const vals = Array.from(document.querySelectorAll(`input[data-group="${groupName}"]:checked`)).map(el => el.value);
  lsSet(storageKey, JSON.stringify(normalizeStoredChecks(groupName, vals)));
}

