function bindAutoSave(){ byId('userName').addEventListener('input', e => { lsSet('gdc_user_name', e.target.value); notifyIndexSync(); }); byId('userEmail').addEventListener('input', e => { lsSet('gdc_user_email', e.target.value); notifyIndexSync(); }); document.querySelectorAll('input[data-group="q1"]').forEach(el => el.addEventListener('change', () => { saveChecks('q1','gdc_q1_checks_v1'); saveAll(); })); document.querySelectorAll('input[data-group="q2"]').forEach(el => el.addEventListener('change', () => { saveChecks('q2','gdc_q2_checks_v1'); saveAll(); })); const map = {q1TextField:'gdc_q1_text_v1',q2TextField:'gdc_q2_text_v1',q3ShortField:'gdc_q3_short_v1',q3MediumField:'gdc_q3_medium_v1',q3LongField:'gdc_q3_long_v1',q4Field:'gdc_q4_text_v1',q5Field:'gdc_q5_text_v1',q6Field:'gdc_q6_text_v1',q7Field:'gdc_q7_text_v1',q8Field:'gdc_q8_text_v1',q9ImplField:'gdc_q9_impl_v1',q9AdopField:'gdc_q9_adop_v1'}; Object.entries(map).forEach(([id,key]) => byId(id).addEventListener('input', e => { lsSet(key, e.target.value); saveAll(); })); }
