let gdcSupabase = null;
function initSupabase(){
  if (gdcSupabase) return gdcSupabase;
  if (!window.supabase || !window.supabase.createClient) {
    console.warn('Supabase client no disponible');
    return null;
  }
  gdcSupabase = window.supabase.createClient(GDC_SUPABASE_URL, GDC_SUPABASE_ANON_KEY);
  return gdcSupabase;
}
function withSupabaseTimeout(promise, ms = 12000, label = 'la operación'){
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error('Tiempo de espera agotado al intentar completar ' + label + '.')), ms))
  ]);
}

let reviewCloudPersistTimer = null;
let reviewCloudPersistInFlight = false;
function scheduleCloudPersist(options = {}){
  const delay = Number.isFinite(options.delay) ? options.delay : 1200;
  const immediate = !!options.immediate;
  const silent = options.silent !== false;
  if(reviewCloudPersistTimer){ clearTimeout(reviewCloudPersistTimer); reviewCloudPersistTimer = null; }
  if(immediate){ persistReviewProjectToCloud({ silent }); return; }
  reviewCloudPersistTimer = setTimeout(() => persistReviewProjectToCloud({ silent }), delay);
}
async function persistReviewProjectToCloud(options = {}){
  const { silent = true } = options;
  const client = initSupabase();
  const projectId = lsGet(GDC_PROJECT_ID_KEY, '').trim();
  if(!client || !projectId || reviewCloudPersistInFlight) return;
  reviewCloudPersistInFlight = true;
  try {
    const payload = collectLocalSnapshot();
    const { error } = await withSupabaseTimeout(client.from(GDC_SUPABASE_TABLE).upsert(payload, { onConflict: 'project_id' }), 12000, 'el guardado automático');
    if(error) throw error;
    if(payload.owner_email) lsSet(GDC_LAST_OWNER_EMAIL_KEY, normalizeEmail(payload.owner_email));
  } catch(err){
    console.error('Review autosave error:', err);
    if(!silent){
      const detalle = err?.message || err?.details || err?.hint || 'Sin detalle disponible';
      alert(`No se pudo guardar el proyecto en la base de datos.

${detalle}`);
    }
  } finally {
    reviewCloudPersistInFlight = false;
  }
}
function generateProjectId(){
  const rand = Math.random().toString(36).slice(2,8);
  return `gdc-${Date.now()}-${rand}`;
}
function getProjectId(){
  let id = lsGet(GDC_PROJECT_ID_KEY, '').trim();
  if(!id){
    id = generateProjectId();
    lsSet(GDC_PROJECT_ID_KEY, id);
  }
  return id;
}
function setCloudStatus(message, tone='default'){
  const el = byId('cloudStatus');
  if(!el) return;
  el.textContent = message;
  el.dataset.tone = tone;
}
function normalizeEmail(value=''){ return String(value || '').trim().toLowerCase(); }
function formatCloudDate(value){
  if(!value) return 'Sin fecha';
  const date = new Date(value);
  if(Number.isNaN(date.getTime())) return value;
  return date.toLocaleString('es-AR', { dateStyle:'short', timeStyle:'short' });
}
function setProjectsHint(message, tone='default'){
  const el = byId('projectsHint');
  if(!el) return;
  el.textContent = message;
  el.dataset.tone = tone;
  el.style.color = tone === 'error' ? 'rgba(255,187,187,.92)' : tone === 'success' ? 'rgba(191,243,184,.96)' : 'rgba(234,245,231,.72)';
}
function renderProjectsList(projects = []){
  const wrap = byId('projectsList');
  if(!wrap) return;
  const activeId = lsGet(GDC_PROJECT_ID_KEY, '').trim();
  if(!projects.length){
    wrap.innerHTML = '<div class="projectEmpty">No hay proyectos guardados todavía para este correo.</div>';
    return;
  }
  wrap.innerHTML = projects.map((item) => {
    const title = escapeHtml(item.project_title || 'Proyecto sin título');
    const pid = escapeHtml(item.project_id || '');
    const owner = escapeHtml(item.owner_name || item.owner_email || 'Sin nombre');
    const date = escapeHtml(formatCloudDate(item.updated_at));
    const active = item.project_id === activeId;
    return `<article class="projectCard${active ? ' active' : ''}">
      <div class="projectInfo">
        <div class="projectTitle">${title}</div>
        <div class="projectMeta">${owner}</div>
        <div class="projectSubmeta">ID ${pid} · Actualizado ${date}</div>
      </div>
      <div class="projectActions">
        ${active ? '<span class="projectTag">Proyecto actual</span>' : ''}
        <button class="ghostBtn cloudProjectLoadBtn" type="button" data-project-id="${pid}">Abrir</button>
      </div>
    </article>`;
  }).join('');
  wrap.querySelectorAll('.cloudProjectLoadBtn').forEach((btn) => {
    btn.addEventListener('click', async () => {
      const projectIdField = byId('projectIdField');
      if(projectIdField) projectIdField.value = btn.dataset.projectId || '';
      await loadProjectFromCloud(btn.dataset.projectId || '');
    });
  });
}
async function fetchProjectsForCurrentEmail(options = {}){
  const { silent = false } = options;
  const client = initSupabase();
  if(!client){
    if(!silent) setProjectsHint('No se pudo inicializar Supabase.', 'error');
    return [];
  }
  const email = normalizeEmail(byId('userEmail')?.value || lsGet('gdc_user_email', ''));
  if(!email){
    renderProjectsList([]);
    if(!silent) setProjectsHint('Cargá tu correo para ver tus proyectos guardados.', 'default');
    return [];
  }
  lsSet(GDC_LAST_OWNER_EMAIL_KEY, email);
  try {
    if(!silent) setProjectsHint('Buscando tus proyectos guardados…');
    const { data, error } = await withSupabaseTimeout(client
      .from(GDC_SUPABASE_TABLE)
      .select('project_id, project_title, owner_name, owner_email, updated_at')
      .eq('owner_email', email)
      .order('updated_at', { ascending: false })
      .limit(12), 8000, 'la carga de proyectos');
    if(error) throw error;
    renderProjectsList(data || []);
    if(!silent) setProjectsHint(data && data.length ? 'Tus proyectos fueron cargados correctamente.' : 'No hay proyectos guardados todavía para este correo.', data && data.length ? 'success' : 'default');
    return data || [];
  } catch(err){
    console.error('Cloud list error:', err);
    renderProjectsList([]);
    if(!silent) setProjectsHint('No se pudo cargar la lista de proyectos.', 'error');
    return [];
  }
}

function collectLocalSnapshot(){
  const keys = [
    'gdc_user_name','gdc_user_email','gdc_q1_checks_v1','gdc_q1_text_v1','gdc_q1_progress',
    'gdc_q2_checks_v1','gdc_q2_text_v1','gdc_q3_short_v1','gdc_q3_medium_v1','gdc_q3_long_v1',
    'gdc_q4_text_v1','gdc_q5_text_v1','gdc_q6_text_v1','gdc_q7_text_v1','gdc_q8_text_v1',
    'gdc_q9_impl_v1','gdc_q9_adop_v1','gdc_map_done_v1'
  ];
  const answers = {};
  keys.forEach((key)=>{ answers[key] = lsGet(key, ''); });
  const doneList = parseJSON(lsGet('gdc_map_done_v1','[]'), []);
  const doneCount = Array.isArray(doneList) ? doneList.length : 0;
  const projectState = {
    done_questions: doneCount,
    total_questions: 9,
    completion_percent: Math.round((doneCount / 9) * 100),
    is_complete: doneCount === 9,
    last_completed_question: doneCount ? Math.max(...doneList) : 0,
    status_label: doneCount === 9 ? 'completo' : (doneCount > 0 ? 'en_progreso' : 'nuevo')
  };
  answers.project_state = projectState;
  return {
    project_id: getProjectId(),
    owner_name: byId('userName')?.value?.trim() || lsGet('gdc_user_name',''),
    owner_email: byId('userEmail')?.value?.trim() || lsGet('gdc_user_email',''),
    project_title: byId('q1TextField')?.value?.trim() || 'Proyecto sin título',
    answers,
    review_answers: {
      q1_checks: Array.from(document.querySelectorAll('#q1ChecksWrap input[type="checkbox"]:checked')).map((el)=>el.value),
      q2_checks: Array.from(document.querySelectorAll('#q2ChecksWrap input[type="checkbox"]:checked')).map((el)=>el.value),
      q1_text: byId('q1TextField')?.value?.trim() || '',
      q2_text: byId('q2TextField')?.value?.trim() || '',
      q3_short: byId('q3ShortField')?.value?.trim() || '',
      q3_medium: byId('q3MediumField')?.value?.trim() || '',
      q3_long: byId('q3LongField')?.value?.trim() || '',
      q4: byId('q4Field')?.value?.trim() || '',
      q5: byId('q5Field')?.value?.trim() || '',
      q6: byId('q6Field')?.value?.trim() || '',
      q7: byId('q7Field')?.value?.trim() || '',
      q8: byId('q8Field')?.value?.trim() || '',
      q9_impl: byId('q9ImplField')?.value?.trim() || '',
      q9_adop: byId('q9AdopField')?.value?.trim() || '',
      project_state: projectState
    },
    updated_at: new Date().toISOString()
  };
}
async function saveProjectToCloud(){
  saveAll();
  const client = initSupabase();
  if(!client){
    alert('No se pudo inicializar Supabase.');
    return;
  }
  const btn = byId('cloudSaveBtn');
  const original = btn ? btn.textContent : '';
  try {
    if(btn){ btn.disabled = true; btn.textContent = 'Guardando…'; }
    setCloudStatus('Guardando en nube…');
    const payload = collectLocalSnapshot();
    const { error } = await withSupabaseTimeout(client.from(GDC_SUPABASE_TABLE).upsert(payload, { onConflict: 'project_id' }), 12000, 'el guardado automático');
    if(error) throw error;
    lsSet(GDC_PROJECT_ID_KEY, payload.project_id);
    setCloudStatus(`Proyecto guardado en nube · ID ${payload.project_id}`, 'success');

    if(payload.owner_email) lsSet(GDC_LAST_OWNER_EMAIL_KEY, normalizeEmail(payload.owner_email));
    notifyIndexSync();
    if ((byId('userEmail')?.value || lsGet('gdc_user_email','')).trim()) await fetchProjectsForCurrentEmail({ silent: true });
  } catch(err){
    console.error('Cloud save error:', err);
    setCloudStatus('No se pudo guardar en nube.', 'error');
    alert('No se pudo guardar en Supabase. Revisá la consola y confirmá que exista la tabla gdc_projects.');
  } finally {
    if(btn){ btn.disabled = false; btn.textContent = original; }
  }
}
function applySnapshotToLocal(snapshot){
  if(!snapshot || !snapshot.answers) return;
  Object.entries(snapshot.answers).forEach(([key, value])=> lsSet(key, typeof value === 'string' ? value : JSON.stringify(value)));
  if(snapshot.project_id) lsSet(GDC_PROJECT_ID_KEY, snapshot.project_id);
}
async function loadProjectFromCloud(forcedProjectId){
  const client = initSupabase();
  if(!client){
    alert('No se pudo inicializar Supabase.');
    return;
  }
  const current = lsGet(GDC_PROJECT_ID_KEY, '').trim();
  const requested = String(forcedProjectId || current || '').trim();
  if(!requested) return;
  const btn = byId('cloudLoadBtn');
  const original = btn ? btn.textContent : '';
  try {
    if(btn){ btn.disabled = true; btn.textContent = 'Cargando…'; }
    setCloudStatus('Cargando proyecto desde nube…');
    const { data, error } = await withSupabaseTimeout(client.from(GDC_SUPABASE_TABLE).select('*').eq('project_id', requested).single(), 12000, 'la carga del proyecto');
    if(error) throw error;
    applySnapshotToLocal(data);
    fillForm();
    saveAll();
    setCloudStatus(`Proyecto cargado · ID ${requested}`, 'success');

    if ((byId('userEmail')?.value || lsGet('gdc_user_email','')).trim()) await fetchProjectsForCurrentEmail({ silent: true });
  } catch(err){
    console.error('Cloud load error:', err);
    setCloudStatus('No se pudo cargar el proyecto.', 'error');
    alert('No se pudo cargar el proyecto desde Supabase. Revisá el ID y la consola.');
  } finally {
    if(btn){ btn.disabled = false; btn.textContent = original; }
  }
}
const gdcChannel = (() => { try { return new BroadcastChannel('gdc_sync_channel_v2'); } catch (e) { return null; } })();
function notifyIndexSync(){
  const payload = { type: GDC_SYNC_EVENT, at: Date.now() };
  try { if (window.opener && !window.opener.closed) window.opener.postMessage(payload, '*'); } catch(e){}
  try { if (gdcChannel) gdcChannel.postMessage(payload); } catch(e){}
}
function saveAll(){
  lsSet('gdc_user_name', byId('userName').value);
  lsSet('gdc_user_email', byId('userEmail').value);
  saveChecks('q1','gdc_q1_checks_v1');
  saveChecks('q2','gdc_q2_checks_v1');
  const map = {q1TextField:'gdc_q1_text_v1',q2TextField:'gdc_q2_text_v1',q3ShortField:'gdc_q3_short_v1',q3MediumField:'gdc_q3_medium_v1',q3LongField:'gdc_q3_long_v1',q4Field:'gdc_q4_text_v1',q5Field:'gdc_q5_text_v1',q6Field:'gdc_q6_text_v1',q7Field:'gdc_q7_text_v1',q8Field:'gdc_q8_text_v1',q9ImplField:'gdc_q9_impl_v1',q9AdopField:'gdc_q9_adop_v1'};
  Object.entries(map).forEach(([id,key]) => lsSet(key, byId(id).value));
  const q1Checks = parseJSON(lsGet('gdc_q1_checks_v1','[]'), []);
  const q2Checks = parseJSON(lsGet('gdc_q2_checks_v1','[]'), []);
  const done = [];
  if (q1Checks.length && byId('q1TextField').value.trim()) done.push(1);
  if (q2Checks.length && byId('q2TextField').value.trim()) done.push(2);
  if (byId('q3ShortField').value.trim() && byId('q3MediumField').value.trim() && byId('q3LongField').value.trim()) done.push(3);
  if (byId('q4Field').value.trim()) done.push(4);
  if (byId('q5Field').value.trim()) done.push(5);
  if (byId('q6Field').value.trim()) done.push(6);
  if (byId('q7Field').value.trim()) done.push(7);
  if (byId('q8Field').value.trim()) done.push(8);
  if (byId('q9ImplField').value.trim() && byId('q9AdopField').value.trim()) done.push(9);
  lsSet('gdc_q1_progress', JSON.stringify({ tipos: q1Checks, descripcion: byId('q1TextField').value || '' }));
  lsSet('gdc_q2_progress', JSON.stringify({ tipos: q2Checks, descripcion: byId('q2TextField').value || '' }));
  lsSet('gdc_map_done_v1', JSON.stringify(done));
  notifyIndexSync();
  scheduleCloudPersist({ delay: 700, silent: true });
}
function getSelected(group){ return Array.from(document.querySelectorAll(`input[data-group="${group}"]:checked`)).map(el => el.parentElement.innerText.trim()); }
function collectSections(){ saveAll(); return [
  { title:'Bloque 1 · Direccionalidad estratégica', items:[{q:'1. ¿Qué cambia?', a:[['Tipo de cambio', getSelected('q1').join(', ') || '—'], ['Descripción del cambio', byId('q1TextField').value.trim() || '—']]}, {q:'2. ¿Por qué cambia?', a:[['Motivadores', getSelected('q2').join(', ') || '—'], ['Explicación', byId('q2TextField').value.trim() || '—']]}, {q:'3. ¿Para qué cambia?', a:[['Corto plazo', byId('q3ShortField').value.trim() || '—'], ['Mediano plazo', byId('q3MediumField').value.trim() || '—'], ['Largo plazo', byId('q3LongField').value.trim() || '—']]} ]},
  { title:'Bloque 2 · Impacto humano', items:[{q:'4. ¿A quién impacta?', a:[[null, byId('q4Field').value.trim() || '—']]}, {q:'5. ¿Qué harán distinto?', a:[[null, byId('q5Field').value.trim() || '—']]}, {q:'6. Riesgos generales', a:[[null, byId('q6Field').value.trim() || '—']]} ]},
  { title:'Bloque 3 · Indicadores', items:[{q:'7. Narrativa del cambio', a:[[null, byId('q7Field').value.trim() || '—']]}, {q:'8. ¿Cómo lo vas a desplegar?', a:[[null, byId('q8Field').value.trim() || '—']]}, {q:'9. Indicadores de adopción', a:[['KPI de implementación', byId('q9ImplField').value.trim() || '—'], ['KPI de adopción', byId('q9AdopField').value.trim() || '—']]} ]}
]; }
function makeQuestionBlock(item){ const div = document.createElement('div'); div.className='pdf-question'; div.innerHTML = `<h3>${escapeHtml(item.q)}</h3>` + item.a.map(([sub,txt]) => sub ? `<div class="pdf-sub">${escapeHtml(sub)}</div><p>${escapeHtml(txt)}</p>` : `<p>${escapeHtml(txt)}</p>`).join(''); return div; }
function createPage(isFirst, name, email){ const page = document.createElement('div'); page.className='pdf-page'; const header = document.createElement('div'); if (isFirst) { header.innerHTML = `<img class="pdf-header-logo" src="${PDF_LOGO_DATA_URL}" alt="GdC"><h1 class="pdf-title">Mapa del Cambio</h1><div class="pdf-meta">${name ? 'Nombre: ' + escapeHtml(name) : ''}${name && email ? ' · ' : ''}${email ? 'Correo: ' + escapeHtml(email) : ''}</div>`; } else { header.className='pdf-cont-header'; header.innerHTML = `<p class="pdf-cont-mini">Mapa del Cambio</p><img class="pdf-cont-logo" src="${PDF_LOGO_DATA_URL}" alt="GdC">`; } page.appendChild(header); const content = document.createElement('div'); content.className='pdf-page-content'; content.style.height = isFirst ? 'calc(1123px - 74px - 62px - 250px)' : 'calc(1123px - 74px - 62px - 80px)'; page.appendChild(content); return [page, content]; }
function buildPaginatedPages(){ const measure = byId('pdfMeasure'); measure.innerHTML=''; const name = byId('userName').value.trim(); const email = byId('userEmail').value.trim(); const sections = collectSections(); const pages=[]; let [page, content] = createPage(true, name, email); measure.appendChild(page); pages.push(page); const maxHeight = () => content.clientHeight; let lastSectionTitle='';
  function ensureFits(node, sectionTitle){ content.appendChild(node); if (content.scrollHeight > maxHeight()) { content.removeChild(node); [page, content] = createPage(false, name, email); measure.appendChild(page); pages.push(page); if (sectionTitle) { const sectionHead = document.createElement('h2'); sectionHead.className='pdf-section-title'; sectionHead.textContent = sectionTitle; content.appendChild(sectionHead); lastSectionTitle = sectionTitle; } content.appendChild(node); } }
  sections.forEach(section => { const head = document.createElement('h2'); head.className='pdf-section-title'; head.textContent = section.title; ensureFits(head, null); lastSectionTitle = section.title; section.items.forEach(item => { const node = makeQuestionBlock(item); ensureFits(node, lastSectionTitle); }); });
  return pages; }

function pdfEscape(text){
  return String(text ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n/g, '\\n');
}
function bytesFromBinaryString(str){
  const out = new Uint8Array(str.length);
  for(let i=0;i<str.length;i++) out[i] = str.charCodeAt(i) & 255;
  return out;
}
function dataUrlToBinary(dataUrl){
  return atob(String(dataUrl).split(',')[1] || '');
}
function dataUrlMime(dataUrl){
  const m = String(dataUrl).match(/^data:([^;]+);/i);
  return m ? m[1].toLowerCase() : 'image/jpeg';
}
function createMeasureContext(){
  const c = document.createElement('canvas');
  c.width = 1200; c.height = 200;
  return c.getContext('2d');
}
function wrapPdfText(ctx, text, maxWidth, font){
  const raw = String(text ?? '—').replace(/\r\n/g,'\n').replace(/\r/g,'\n');
  const paragraphs = raw.split('\n');
  const lines = [];
  ctx.font = font;
  for(const para of paragraphs){
    const cleaned = para.trim();
    if(!cleaned){ lines.push(''); continue; }
    const words = cleaned.split(/\s+/);
    let line = '';
    for(const word of words){
      const test = line ? line + ' ' + word : word;
      if(ctx.measureText(test).width <= maxWidth || !line){
        line = test;
      } else {
        lines.push(line);
        line = word;
      }
    }
    if(line) lines.push(line);
  }
  return lines.length ? lines : ['—'];
}
function buildPdfLayout(){
  const ctx = createMeasureContext();
  const pageW = 595.28, pageH = 841.89;
  const marginX = 52, topFirst = 56, topOther = 36, bottom = 52;
  const contentW = pageW - marginX * 2;
  const colors = {
    dark: [0.07,0.20,0.11],
    body: [0.14,0.14,0.14],
    muted: [0.30,0.37,0.30],
    bandFill: [0.93,0.96,0.92],
    bandStroke: [0.56,0.82,0.54],
    sub: [0.20,0.32,0.21]
  };
  const font = {
    title: 'bold 24px Helvetica',
    meta: '12px Helvetica',
    section: 'bold 16px Helvetica',
    q: 'bold 13px Helvetica',
    sub: 'bold 11px Helvetica',
    body: '11px Helvetica',
    cont: 'bold 12px Helvetica'
  };
  const lh = { meta: 16, q: 16, sub: 13, body: 14 };
  const pages = [];
  let pageIndex = 0;
  function newPage(){
    pageIndex += 1;
    const isFirst = pageIndex === 1;
    const page = { isFirst, ops: [], y: isFirst ? topFirst : topOther };
    pages.push(page);
    return page;
  }
  let page = newPage();
  function ensureSpace(height, sectionTitle){
    if(page.y + height <= pageH - bottom) return;
    page = newPage();
    if(sectionTitle) drawSectionTitle(sectionTitle, true);
  }
  function drawText(text, x, yTop, fontKey, size, colorKey){
    const pdfY = pageH - yTop - size;
    page.ops.push({type:'text', text, x, y: pdfY, font: fontKey, size, color: colors[colorKey]});
  }
  function drawRect(x, yTop, w, h, fillKey){
    const pdfY = pageH - yTop - h;
    page.ops.push({type:'rect', x, y: pdfY, w, h, fill: colors[fillKey]});
  }
  function drawSectionTitle(title, continued){
    const bandH = 34;
    ensureSpace(bandH + 18, null);
    drawRect(marginX, page.y, contentW, bandH, 'bandFill');
    drawRect(marginX, page.y, 6, bandH, 'bandStroke');
    drawText(continued ? title + ' (continúa)' : title, marginX + 14, page.y + 8, 'F2', 16, 'dark');
    page.y += bandH + 16;
  }
  function drawHeader(name, email){
    if(page.isFirst){
      page.ops.push({type:'logo', variant:'main'});
      page.y = 178;
      drawText('Mapa del Cambio', marginX, page.y, 'F2', 24, 'dark');
      page.y += 34;
      const meta = `${name ? 'Nombre: ' + name : ''}${name && email ? ' · ' : ''}${email ? 'Correo: ' + email : ''}`;
      if(meta){
        const metaLines = wrapPdfText(ctx, meta, contentW, font.meta);
        for(const line of metaLines){ drawText(line, marginX, page.y, 'F1', 12, 'muted'); page.y += lh.meta; }
      }
      page.y += 10;
    } else {
      page.ops.push({type:'logo', variant:'mini'});
      drawText('Mapa del Cambio', marginX, page.y, 'F2', 12, 'dark');
      page.y += 24;
    }
  }
  const name = byId('userName').value.trim();
  const email = byId('userEmail').value.trim();
  drawHeader(name, email);

  const sections = collectSections();
  for(const section of sections){
    drawSectionTitle(section.title, false);
    for(const item of section.items){
      const qLines = wrapPdfText(ctx, item.q, contentW, font.q);
      const answerBlocks = [];
      let needed = qLines.length * lh.q + 6;
      for(const [sub, txt] of item.a){
        const block = { sub: sub || null, lines: wrapPdfText(ctx, txt || '—', contentW, font.body) };
        if(block.sub) needed += lh.sub + 2;
        needed += block.lines.length * lh.body + 6;
        answerBlocks.push(block);
      }
      ensureSpace(needed + 8, section.title);
      for(const line of qLines){ drawText(line, marginX, page.y, 'F2', 13, 'dark'); page.y += lh.q; }
      page.y += 2;
      for(const block of answerBlocks){
        if(block.sub){ drawText(block.sub, marginX, page.y, 'F2', 11, 'sub'); page.y += lh.sub + 1; }
        for(const line of block.lines){ drawText(line, marginX, page.y, 'F1', 11, 'body'); page.y += lh.body; }
        page.y += 6;
      }
      page.y += 2;
    }
  }
  return pages;
}
async function getLogoJpeg(){
  const img = new Image();
  img.decoding = 'sync';
  const dataUrl = PDF_LOGO_DATA_URL;
  await new Promise((resolve, reject) => { img.onload = resolve; img.onerror = reject; img.src = dataUrl; });
  const canvas = document.createElement('canvas');
  const w = img.naturalWidth || 512;
  const h = img.naturalHeight || 256;
  canvas.width = w; canvas.height = h;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0,0,w,h);
  ctx.drawImage(img,0,0,w,h);
  return { dataUrl: canvas.toDataURL('image/jpeg', 0.92), width: w, height: h };
}
function buildPdfBinary(pages, logo){
  const pageW = 595.28, pageH = 841.89;
  const objects = [];
  const offsets = [];
  const add = (body, isBinary=false) => { objects.push({body, isBinary}); return objects.length; };
  const catalogId = add('');
  const pagesId = add('');
  const fontRegularId = add('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding >>');
  const fontBoldId = add('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding >>');
  const logoBin = dataUrlToBinary(logo.dataUrl);
  const logoId = add(`<< /Type /XObject /Subtype /Image /Width ${logo.width} /Height ${logo.height} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${logoBin.length} >>\nstream\n${logoBin}\nendstream`, true);
  const pageIds = [];
  for(const page of pages){
    let stream = '';
    for(const op of page.ops){
      if(op.type === 'rect'){
        stream += `${op.fill[0].toFixed(3)} ${op.fill[1].toFixed(3)} ${op.fill[2].toFixed(3)} rg\n`;
        stream += `${op.x.toFixed(2)} ${op.y.toFixed(2)} ${op.w.toFixed(2)} ${op.h.toFixed(2)} re f\n`;
      } else if(op.type === 'text'){
        stream += `BT\n`;
        stream += `/${op.font} ${op.size} Tf\n`;
        stream += `${op.color[0].toFixed(3)} ${op.color[1].toFixed(3)} ${op.color[2].toFixed(3)} rg\n`;
        stream += `1 0 0 1 ${op.x.toFixed(2)} ${op.y.toFixed(2)} Tm\n`;
        stream += `(${pdfEscape(op.text)}) Tj\nET\n`;
      } else if(op.type === 'logo'){
        let x, y, w, h;
        if(op.variant === 'main'){
          w = 150; h = w * (logo.height / logo.width); x = (pageW - w) / 2; y = pageH - 48 - h;
        } else {
          w = 72; h = w * (logo.height / logo.width); x = pageW - 52 - w; y = pageH - 28 - h;
        }
        stream += `q\n${w.toFixed(2)} 0 0 ${h.toFixed(2)} ${x.toFixed(2)} ${y.toFixed(2)} cm\n/Im1 Do\nQ\n`;
      }
    }
    const contentId = add(`<< /Length ${stream.length} >>\nstream\n${stream}endstream`, true);
    const pageId = add(`<< /Type /Page /Parent ${pagesId} 0 R /MediaBox [0 0 ${pageW} ${pageH}] /Resources << /Font << /F1 ${fontRegularId} 0 R /F2 ${fontBoldId} 0 R >> /XObject << /Im1 ${logoId} 0 R >> >> /Contents ${contentId} 0 R >>`);
    pageIds.push(pageId);
  }
  objects[catalogId-1].body = `<< /Type /Catalog /Pages ${pagesId} 0 R >>`;
  objects[pagesId-1].body = `<< /Type /Pages /Count ${pageIds.length} /Kids [ ${pageIds.map(id => id + ' 0 R').join(' ')} ] >>`;
  let pdf = '%PDF-1.4\n%\xFF\xFF\xFF\xFF\n';
  offsets[0] = 0;
  for(let i=0;i<objects.length;i++){
    offsets[i+1] = pdf.length;
    pdf += `${i+1} 0 obj\n${objects[i].body}\nendobj\n`;
  }
  const xrefPos = pdf.length;
  pdf += `xref\n0 ${objects.length+1}\n0000000000 65535 f \n`;
  for(let i=1;i<=objects.length;i++) pdf += `${String(offsets[i]).padStart(10,'0')} 00000 n \n`;
  pdf += `trailer\n<< /Size ${objects.length+1} /Root ${catalogId} 0 R >>\nstartxref\n${xrefPos}\n%%EOF`;
  return new Blob([bytesFromBinaryString(pdf)], {type:'application/pdf'});
}
async function triggerBlobDownload(blob, filename){
  const blobUrl = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = blobUrl;
  a.download = filename;
  a.rel = 'noopener';
  a.style.display = 'none';
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { a.remove(); URL.revokeObjectURL(blobUrl); }, 5000);
  return true;
}
async function downloadPdf(){
  const btn = byId('downloadPdfBtn');
  const original = btn.textContent;
  try {
    saveAll();
    btn.disabled = true;
    btn.textContent = 'Generando PDF…';
    const pages = buildPdfLayout();
    const logo = await getLogoJpeg();
    const blob = buildPdfBinary(pages, logo);
    const safeName = (byId('userName').value.trim() || 'mapa-del-cambio')
      .toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
      .replace(/[^a-z0-9\-\s]/g,'')
      .replace(/\s+/g,'-')
      .replace(/-+/g,'-');
    await triggerBlobDownload(blob, `${safeName}-mapa-del-cambio.pdf`);
  } catch(err) {
    console.error('PDF generation error:', err);
    alert('No se pudo generar el PDF. Revisá la consola del navegador para ver el error exacto.');
  } finally {
    btn.textContent = original;
    btn.disabled = false;
  }
}

function startNewProject(){
  if(!confirm('Se va a preparar un proyecto nuevo en esta revisión. Los cambios actuales ya guardados en nube no se pierden. ¿Querés continuar?')) return;
  const newId = generateProjectId();
  lsSet(GDC_PROJECT_ID_KEY, newId);
  const field = byId('projectIdField');
  if(field) field.value = newId;
  setCloudStatus(`Proyecto nuevo listo · ID ${newId}`,'success');
}

