byId('backToMapBtn')?.addEventListener('click', () => {
  try {
    if (window.opener && !window.opener.closed) {
      window.opener.focus();
      try { window.opener.postMessage({ type: 'gdc_go_to_map_v1' }, '*'); } catch (e) {}
      window.close();
      return;
    }
  } catch (e) {}
  window.location.href = 'index.html#mapa';
});
