function refreshFromStorage(){
  const active = document.activeElement;
  const activeId = active && active.id ? active.id : '';
  const valueMap = {q1TextField:'gdc_q1_text_v1',q2TextField:'gdc_q2_text_v1',q3ShortField:'gdc_q3_short_v1',q3MediumField:'gdc_q3_medium_v1',q3LongField:'gdc_q3_long_v1',q4Field:'gdc_q4_text_v1',q5Field:'gdc_q5_text_v1',q6Field:'gdc_q6_text_v1',q7Field:'gdc_q7_text_v1',q8Field:'gdc_q8_text_v1',q9ImplField:'gdc_q9_impl_v1',q9AdopField:'gdc_q9_adop_v1'};
  if(activeId !== 'userName') byId('userName').value = lsGet('gdc_user_name');
  if(activeId !== 'userEmail') byId('userEmail').value = lsGet('gdc_user_email');
  const q1Stored = parseJSON(lsGet('gdc_q1_checks_v1','[]'), []);
  const q2Stored = parseJSON(lsGet('gdc_q2_checks_v1','[]'), []);
  document.querySelectorAll('input[data-group="q1"]').forEach(el => { if(active !== el) el.checked = q1Stored.includes(el.value); });
  document.querySelectorAll('input[data-group="q2"]').forEach(el => { if(active !== el) el.checked = q2Stored.includes(el.value); });
  Object.entries(valueMap).forEach(([id,key]) => {
    const el = byId(id);
    if(el && activeId !== id) el.value = lsGet(key);
  });
}
window.addEventListener('storage', (event) => {
  if(!event.key || String(event.key).startsWith('gdc_')) refreshFromStorage();
});
window.addEventListener('focus', refreshFromStorage);
document.addEventListener('visibilitychange', () => { if(!document.hidden) refreshFromStorage(); });
if(gdcChannel){
  gdcChannel.addEventListener('message', (event) => {
    if(event && event.data && event.data.type === GDC_SYNC_EVENT) refreshFromStorage();
  });
}

